DB=/opt/battletoads-double-dragon/backend/database.db
sqlite3 -header -column "$DB" "select ts.id as system_id, ts.name as system_name, count(*) as members_total, sum(case when s.is_active=1 then 1 else 0 end) as members_active, sum(case when lower(coalesce(s.state,''))!='flat' then 1 else 0 end) as members_nonflat, sum(case when trim(coalesce(s.last_signal,''))!='' then 1 else 0 end) as with_last_signal, sum(case when trim(coalesce(s.last_error,''))!='' then 1 else 0 end) as with_last_error, min(s.updated_at) as min_updated_at, max(s.updated_at) as max_updated_at from trading_systems ts join trading_system_members tsm on tsm.system_id=ts.id and tsm.is_enabled=1 join strategies s on s.id=tsm.strategy_id where ts.name like 'ALGOFUND_MASTER::%' and ts.is_active=1 group by ts.id, ts.name order by ts.id desc;"